import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon, Badge } from 'decantr/components';

code.example:
function LeaseOverview({ lease }) {
  const { div, h2, span, dl, dt, dd, p } = tags;
  const daysRemaining = Math.ceil((new Date(lease.endDate) - new Date()) / (1000 * 60 * 60 * 24));
  const statusColor = daysRemaining > 60 ? 'success' : daysRemaining > 0 ? 'warning' : 'danger';
  const statusText = daysRemaining > 60 ? 'Active' : daysRemaining > 0 ? `${daysRemaining} days left` : 'Expired';

  return div({ class: css('estate-card _p6') },
    div({ class: css('_flex _jcsb _aic _mb6') },
      div({},
        h2({ class: css('_heading4 _mb1') }, `Lease #${lease.id}`),
        p({ class: css('_textsm _fgmuted') }, `${lease.propertyName} - Unit ${lease.unitNumber}`)
      ),
      div({ class: css('_flex _gap2') },
        Badge({ variant: statusColor }, statusText),
        Button({ variant: 'outline', size: 'sm' }, icon('download'), 'Download')
      )
    ),
    div({ class: css('_grid _cols2 _gap6 _mb6') },
      div({},
        span({ class: css('_textxs _fgmuted _block _mb2') }, 'Tenant'),
        p({ class: css('_font500') }, lease.tenantName),
        p({ class: css('_textsm _fgmuted') }, lease.tenantEmail)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block _mb2') }, 'Property Owner'),
        p({ class: css('_font500') }, lease.ownerName),
        p({ class: css('_textsm _fgmuted') }, lease.ownerEmail)
      )
    ),
    div({ class: css('_grid _cols4 _gap4 _p4 _bgSurfaceRaised _r2 _mb6') },
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Start Date'),
        span({ class: css('_font500') }, lease.startDate)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'End Date'),
        span({ class: css('_font500') }, lease.endDate)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Monthly Rent'),
        span({ class: css('_font500') }, `$${lease.rent.toLocaleString()}`)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Security Deposit'),
        span({ class: css('_font500') }, `$${lease.deposit.toLocaleString()}`)
      )
    ),
    lease.terms?.length > 0 ? div({ class: css('_mb6') },
      span({ class: css('_textsm _font500 _block _mb2') }, 'Lease Terms'),
      div({ class: css('_flex _flexwrap _gap2') },
        ...lease.terms.map(term => Badge({ variant: 'outline' }, term))
      )
    ) : null,
    lease.documents?.length > 0 ? div({ class: css('_mb6') },
      span({ class: css('_textsm _font500 _block _mb2') }, 'Documents'),
      div({ class: css('_flex _col _gap2') },
        ...lease.documents.map(doc =>
          div({ class: css('_flex _aic _gap2 _p2 _bgSurfaceRaised _r1') },
            icon('file-text', { size: '16' }),
            span({ class: css('_flex1 _textsm') }, doc.name),
            Button({ variant: 'ghost', size: 'sm' }, icon('download', { size: '14' }))
          )
        )
      )
    ) : null,
    div({ class: css('_flex _gap2 _pt4 _borderT') },
      Button({ variant: 'primary' }, icon('refresh-cw'), 'Renew Lease'),
      Button({ variant: 'outline' }, icon('edit'), 'Amend'),
      Button({ variant: 'outline', class: css('_fgdanger _hoverBgDanger/10') }, 'Terminate')
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Input, Select } from 'decantr/components';

code.example:
function LeaseEditForm({ lease, onSave, onCancel }) {
  const { div, form, h2, label } = tags;
  const [formData, setFormData] = createSignal(lease);

  return div({ class: css('estate-card _p6') },
    h2({ class: css('_heading4 _mb6') }, lease.id ? 'Edit Lease' : 'New Lease'),
    form({ class: css('_flex _col _gap4'), onsubmit: e => { e.preventDefault(); onSave(formData()); } },
      div({ class: css('_grid _cols2 _gap4') },
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Start Date'),
          Input({ type: 'date', value: formData().startDate, oninput: e => setFormData({ ...formData(), startDate: e.target.value }) })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'End Date'),
          Input({ type: 'date', value: formData().endDate, oninput: e => setFormData({ ...formData(), endDate: e.target.value }) })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Monthly Rent'),
          Input({ type: 'number', value: formData().rent, oninput: e => setFormData({ ...formData(), rent: parseInt(e.target.value) }) })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Security Deposit'),
          Input({ type: 'number', value: formData().deposit, oninput: e => setFormData({ ...formData(), deposit: parseInt(e.target.value) }) })
        )
      ),
      div({ class: css('_flex _jce _gap2 _pt4 _borderT') },
        Button({ type: 'button', variant: 'outline', onclick: onCancel }, 'Cancel'),
        Button({ type: 'submit', variant: 'primary' }, 'Save Lease')
      )
    )
  );
}

